"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";

const ROPE_LENGTH = 20;
const PRESETS = [
  { l: 8, w: 2, label: "长8、宽2" },
  { l: 7, w: 3, label: "长7、宽3" },
  { l: 6, w: 4, label: "长6、宽4" },
  { l: 5, w: 5, label: "长5、宽5（正方形）" },
];

type Phase = "rope" | "challenge" | "done";

export default function TransformPage() {
  const [phase, setPhase] = useState<Phase>("rope");
  const [length, setLength] = useState<number>(8);
  const width = ROPE_LENGTH / 2 - length;
  const [challengeInput, setChallengeInput] = useState("");
  const [encourageMsg, setEncourageMsg] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const challengeRef = useRef<HTMLDivElement>(null);

  const handleChallengeCheck = () => {
    const val = parseInt(challengeInput, 10);
    if (val === 4) {
      setPhase("done");
      setEncourageMsg("");
    } else {
      setEncourageMsg(getRandomEncourage());
      triggerShake(challengeRef.current);
      setTimeout(() => setEncourageMsg(""), 2000);
    }
  };

  const nextStep = getNextStep("perimeter", "transform");

  // SVG 尺寸
  const UNIT = 24;
  const PAD = 30;
  const svgW = 10 * UNIT + PAD * 2;
  const svgH = 10 * UNIT + PAD * 2;

  return (
    <StepShell topicId="perimeter" stepId="transform">
      {phase === "rope" && (
        <div className="space-y-6">
          {/* 绳子展示 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <p className="mb-4 text-sm text-[var(--text-secondary)]">
              一根固定长度的绳子，围成不同的长方形
            </p>
            <div className="flex justify-center">
              <svg width="320" height="80" viewBox="0 0 320 80">
                <polyline
                  points="10,40 35,15 60,40 85,15 110,40 135,15 160,40 185,15 210,40 235,15 260,40 285,15 310,40"
                  fill="none"
                  stroke="var(--accent)"
                  strokeWidth="3"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <text
                  x="160"
                  y="68"
                  textAnchor="middle"
                  fill="var(--text-secondary)"
                  fontSize="14"
                >
                  绳子长 {ROPE_LENGTH}cm
                </text>
              </svg>
            </div>
          </div>

          {/* 交互控制 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="mb-4 flex items-center justify-between">
              <span className="text-sm font-medium text-[var(--text)]">
                调整长：{length}cm
              </span>
              <span className="text-sm text-[var(--text-secondary)]">
                宽：{width}cm
              </span>
            </div>
            <input
              type="range"
              min={1}
              max={9}
              value={length}
              onChange={(e) => setLength(Number(e.target.value))}
              className="w-full"
              style={{ accentColor: "var(--primary)" }}
            />
            <div className="mt-2 flex justify-between text-xs text-[var(--text-muted)]">
              <span>1cm</span>
              <span>9cm</span>
            </div>

            {/* 预设按钮 */}
            <div className="mt-6 grid grid-cols-2 gap-3 sm:grid-cols-4">
              {PRESETS.map((p) => (
                <button
                  key={p.l}
                  onClick={() => setLength(p.l)}
                  className={`rounded-lg border px-3 py-2 text-sm font-medium transition-all hover:scale-105 ${
                    length === p.l
                      ? "border-[var(--primary)] bg-[var(--primary)]/10 text-[var(--primary)]"
                      : "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text)] hover:border-[var(--primary-light)]"
                  }`}
                >
                  {p.label}
                </button>
              ))}
            </div>

            {/* 实时长方形 */}
            <div className="mt-6 flex justify-center">
              <svg
                width={Math.min(svgW, 320)}
                height={Math.min(svgH, 280)}
                viewBox={`0 0 ${svgW} ${svgH}`}
              >
                <rect
                  x={PAD}
                  y={PAD}
                  width={length * UNIT}
                  height={width * UNIT}
                  fill="var(--primary)"
                  fillOpacity={0.15}
                  stroke="var(--primary)"
                  strokeWidth={2}
                  rx={4}
                />
                {/* 长标注 */}
                <text
                  x={PAD + (length * UNIT) / 2}
                  y={PAD - 8}
                  textAnchor="middle"
                  fill="var(--text)"
                  fontSize="13"
                  fontWeight="600"
                >
                  长 {length}cm
                </text>
                {/* 宽标注 */}
                <text
                  x={PAD - 10}
                  y={PAD + (width * UNIT) / 2 + 4}
                  textAnchor="end"
                  fill="var(--text)"
                  fontSize="13"
                  fontWeight="600"
                >
                  宽 {width}cm
                </text>
                {/* 周长标注 */}
                <text
                  x={PAD + (length * UNIT) / 2}
                  y={PAD + width * UNIT + 20}
                  textAnchor="middle"
                  fill="var(--signal-success)"
                  fontSize="13"
                  fontWeight="600"
                >
                  周长 = {ROPE_LENGTH}cm
                </text>
              </svg>
            </div>

            <p className="mt-4 text-center text-sm font-medium text-[var(--primary)]">
              不管长和宽怎么变，周长都是 {ROPE_LENGTH}cm！
            </p>

            <div className="mt-6 flex justify-center">
              <button
                onClick={() => setPhase("challenge")}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                挑战问题 →
              </button>
            </div>
          </div>
        </div>
      )}

      {phase === "challenge" && (
        <div className="space-y-6">
          <div
            ref={challengeRef}
            className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
          >
            <p className="mb-2 text-center font-medium text-[var(--text)]">
              挑战问题
            </p>
            <p className="mb-6 text-center text-sm text-[var(--text-secondary)]">
              用一根 24cm 长的绳子围长方形，如果长是 8cm，宽是多少？
            </p>
            <div className="flex flex-col items-center gap-4">
              <div className="flex items-center gap-2">
                <input
                  type="number"
                  value={challengeInput}
                  onChange={(e) => setChallengeInput(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") handleChallengeCheck();
                  }}
                  className="w-24 rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-3 py-2 text-center text-lg font-bold text-[var(--text)] outline-none focus:border-[var(--primary-light)]"
                  placeholder="?"
                />
                <span className="text-[var(--text)]">cm</span>
              </div>
              <button
                onClick={handleChallengeCheck}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                提交答案
              </button>
              {encourageMsg && (
                <p className="animate-float-in text-sm text-[var(--accent)]">
                  {encourageMsg}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {phase === "done" && (
        <div className="space-y-4">
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="mb-2 text-4xl">🎉</div>
            <p className="text-lg font-semibold text-[var(--text)]">
              {completeMsg}
            </p>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              对！因为 8 + 宽 = 12，所以宽 = 4
            </p>
            <p className="mt-1 text-xs text-[var(--text-muted)]">
              你发现了：绳子的长度（周长）不变，只要调整长，宽就会跟着变
            </p>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="mt-6 inline-flex items-center gap-2 rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
